import React, { useEffect, useState, useMemo } from "react";
import { getIncome, addIncome, logoutUser } from "../api/api";
import IncomeForm from "../components/IncomeForm";
import DashboardCard from "../components/DashboardCard";
import IncomeChart from "../components/IncomeChart";

export default function Dashboard({ onLogout }) {
  const [incomeData, setIncomeData] = useState([]);
  const [loading, setLoading] = useState(false);

  // =========================
  // LOAD DASHBOARD DATA
  // =========================
  const loadDashboard = async () => {
    try {
      setLoading(true);
      const data = await getIncome();
      setIncomeData(data);
    } catch (err) {
      alert(err.message || "Failed to load dashboard");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadDashboard();
  }, []);

  // =========================
  // REAL-TIME CALCULATIONS
  // =========================
  const totalIncome = useMemo(() => {
    return incomeData.reduce((acc, d) => acc + d.amount, 0);
  }, [incomeData]);

  const averageIncome = useMemo(() => {
    if (!incomeData.length) return 0;
    return Math.round(totalIncome / incomeData.length);
  }, [incomeData, totalIncome]);

  const growthRate = useMemo(() => {
    if (incomeData.length < 2) return 0;
    const last = incomeData[incomeData.length - 1].amount;
    const prev = incomeData[incomeData.length - 2].amount;
    return (((last - prev) / prev) * 100).toFixed(1);
  }, [incomeData]);

  const prediction = useMemo(() => {
    if (!incomeData.length) return [];
    const trendFactor = 1 + growthRate / 100 || 1.05;
    return incomeData.map(d => Math.round(d.amount * trendFactor));
  }, [incomeData, growthRate]);

  // =========================
  // ADD INCOME
  // =========================
  const handleAddIncome = async (amount) => {
    await addIncome(amount);
    loadDashboard();
  };

  const handleLogout = () => {
    logoutUser();
    onLogout();
  };

  return (
    <div className="min-h-screen bg-gradient-to-r from-blue-900 via-teal-800 to-green-700 p-6">
      <div className="max-w-6xl mx-auto">

        {/* Header */}
        <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <h2 className="text-4xl font-bold text-white tracking-wide">
            APS AI Financial Dashboard
          </h2>
          <button
            onClick={handleLogout}
            className="bg-red-500 hover:bg-red-600 transition px-5 py-2 rounded-xl text-white font-semibold"
          >
            Logout
          </button>
        </div>

        {/* ======================
            Income Input Form
        ====================== */}
        <IncomeForm onAddIncome={handleAddIncome} />

        {/* ======================
            Stats Cards
        ====================== */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mt-8">
          <DashboardCard title="Total Income" value={`₹ ${totalIncome}`} />
          <DashboardCard title="Average Income" value={`₹ ${averageIncome}`} />
          <DashboardCard title="Growth Rate" value={`${growthRate}%`} />
        </div>

        {/* ======================
            AI Prediction Section
        ====================== */}
        <div className="mt-10 bg-white/10 backdrop-blur-md p-6 rounded-2xl border border-yellow-400 shadow-xl">
          <h3 className="text-2xl text-yellow-300 font-semibold mb-4">
            AI Trend Prediction
          </h3>
          <p className="text-white mb-4">
            Projected next cycle values based on current growth trend:
          </p>
          <div className="text-green-300 font-mono">
            {prediction.join(" , ")}
          </div>
        </div>

        {/* ======================
            Chart Section
        ====================== */}
        <div className="mt-10 bg-white p-6 rounded-2xl shadow-2xl border-4 border-yellow-400">
          <h3 className="text-2xl font-semibold mb-4 text-gray-700">
            Income Analytics
          </h3>
          <IncomeChart data={incomeData.map(d => d.amount)} prediction={prediction} />
        </div>

        {/* Loading */}
        {loading && (
          <div className="text-white mt-4 text-center">Loading data...</div>
        )}

      </div>
    </div>
  );
}
